  uint32_t out_sb_tile_count   = get_arg_val<uint32_t>(26);
  uint32_t out_num_sb_w        = get_arg_val<uint32_t>(27);
  uint32_t out_num_sb_h        = get_arg_val<uint32_t>(28);
